// Configuration des délais max par étape (en heures)
const DELAIS_MAX = {
  'Découpe toile': 4,
  'Couture': 6,
  'Découpe armature': 4,
  'Assemblage': 8,
  'Réglage': 2,
  'Emballage': 2,
  'Expédition': 24
};

const items = $input.all();
const now = new Date();
const alertes = [];

for (const item of items) {
  const fields = item.json.fields || item.json;
  const bonId = fields.produit_id || item.json.id;
  const etape = fields.statut_production || 'Découpe toile';
  const client = fields['Nom (from Client) (from Facture_liee)']?.[0] || 'N/A';
  const designation = fields.Designation || 'N/A';

  // Mapping étape -> champ date début
  const dateFields = {
    'Découpe toile': 'debut_dido',
    'Couture': 'debut_couture',
    'Découpe armature': 'debut_armature',
    'Assemblage': 'debut_assemblage',
    'Réglage': 'debut_reglage',
    'Emballage': 'debut_emballage',
    'Expédition': 'date_expe'
  };

  const dateField = dateFields[etape];
  const dateDebut = fields[dateField] ? new Date(fields[dateField]) : null;

  if (dateDebut) {
    const heuresEcoulees = (now - dateDebut) / (1000 * 60 * 60);
    const delaiMax = DELAIS_MAX[etape] || 24;

    if (heuresEcoulees > delaiMax) {
      const retard = Math.round(heuresEcoulees - delaiMax);
      alertes.push({
        type: 'retard',
        bon_id: bonId,
        etape: etape,
        client: client,
        designation: designation,
        heures_retard: retard,
        message: `⚠️ RETARD: ${bonId} - ${etape} en retard de ${retard}h (Client: ${client})`
      });
    }
  } else {
    // Pas de date de début = étape non commencée
    const dateValidation = fields.date_validation ? new Date(fields.date_validation) : null;
    if (dateValidation) {
      const heuresAttente = (now - dateValidation) / (1000 * 60 * 60);
      if (heuresAttente > 24) {
        alertes.push({
          type: 'non_demarre',
          bon_id: bonId,
          etape: etape,
          client: client,
          designation: designation,
          heures_attente: Math.round(heuresAttente),
          message: `⏳ NON DÉMARRÉ: ${bonId} - ${etape} en attente depuis ${Math.round(heuresAttente)}h (Client: ${client})`
        });
      }
    }
  }
}

// Retourne les alertes
if (alertes.length === 0) {
  return [{json: {has_alerts: false, message: 'Aucune alerte'}}];
}

return alertes.map(a => ({json: {...a, has_alerts: true}}));

// Agrège toutes les alertes en un seul message
const alertes = $input.all();
const retards = alertes.filter(a => a.json.type === 'retard');
const nonDemarres = alertes.filter(a => a.json.type === 'non_demarre');

let message = `🔔 *ALERTES PRODUCTION MON USINE*\n\n`;
message += `📅 ${new Date().toLocaleString('fr-FR')}\n\n`;

if (retards.length > 0) {
  message += `⚠️ *RETARDS (${retards.length})*\n`;
  retards.forEach(a => {
    message += `• ${a.json.bon_id}: ${a.json.etape} (+${a.json.heures_retard}h)\n`;
    message += `  Client: ${a.json.client}\n`;
  });
  message += `\n`;
}

if (nonDemarres.length > 0) {
  message += `⏳ *NON DÉMARRÉS (${nonDemarres.length})*\n`;
  nonDemarres.forEach(a => {
    message += `• ${a.json.bon_id}: en attente depuis ${a.json.heures_attente}h\n`;
    message += `  Client: ${a.json.client}\n`;
  });
}

message += `\n---\nTotal: ${alertes.length} alerte(s)`;

return [{json: {
  message,
  total_alertes: alertes.length,
  retards: retards.length,
  non_demarres: nonDemarres.length
}}];

const items = $input.all();
if (!items || items.length === 0 || !items[0]?.json?.id) {
  return [{ json: { has_stock_alerts: false, stock_alerts: [], message: 'Stocks volets OK' } }];
}

const alerts = items.map(item => {
  const f = item.json.fields || {};
  const designation = f.Designation?.[0] || f.Designation || 'N/A';
  const qte = f.QuantiteDisponible ?? 0;
  const seuil = f.SeuilMin ?? 2;
  const emplacement = f.Emplacement || 'N/A';
  const urgence = qte === 0 ? '🔴 RUPTURE' : '🟡 STOCK BAS';
  return { urgence, designation, qte, seuil, emplacement, has_alerts: true,
    message: `${urgence}: Réappro volet ${designation} : ${qte} restants (seuil: ${seuil})` };
});

const msgLines = alerts.map(a => a.message).join('\n');
const totalRuptures = alerts.filter(a => a.qte === 0).length;
const totalBas = alerts.filter(a => a.qte > 0).length;

return [{ json: {
  has_stock_alerts: true,
  stock_alerts: alerts,
  total_stock_alerts: alerts.length,
  total_ruptures: totalRuptures,
  total_bas: totalBas,
  message_slack: `*📦 Stocks volets bas — ${new Date().toLocaleDateString('fr-FR')}*\n${alerts.map(a => `• ${a.urgence} *${a.designation}* : ${a.qte} restants`).join('\n')}`,
  email_subject: `[Mon Usine] ${totalRuptures} rupture(s), ${totalBas} stock(s) bas — Volets`,
  email_body: `<h3>📦 Stocks Volets Roulants Bas</h3><table border='1' cellpadding='6' style='border-collapse:collapse'><tr><th>Désignation</th><th>Stock</th><th>Seuil</th><th>Emplacement</th><th>Statut</th></tr>${alerts.map(a => `<tr style='color:${a.qte===0?'red':'orange'}'><td>${a.designation}</td><td><b>${a.qte}</b></td><td>${a.seuil}</td><td>${a.emplacement}</td><td>${a.urgence}</td></tr>`).join('')}</table>`
}}];
